window.Java = {
    runJava: function(code, callbacks) {
        console.error('[JDK.js] Runtime tidak tersedia. File vendor/jdk.min.js belum di‑install.');
        var msg = 'JDK.js runtime tidak dapat dimuat.\n\nInstruksi:\n1. Download jdk.min.js dari:\n   https://github.com/marcfasel/jdk.js/releases/download/v0.3.2/jdk.min.js\n2. Simpan sebagai vendor/jdk.min.js di repo Java Learning Path.\n3. Commit, push, dan build ulang.\n4. Hard refresh halaman (Ctrl+Shift+R).';
        if (callbacks && callbacks.error) callbacks.error(msg);
        else alert(msg);
    }
};
